import React, { useEffect, useState } from 'react';
import axios from 'axios';

const BookManagement = () => {
  const [books, setBooks] = useState([]);
  const [categories, setCategories] = useState([]);
  const [form, setForm] = useState({ title: '', author: '', isbn: '', category: '', availableCopies: 0, totalCopies: 0 });

  useEffect(() => {
    fetchBooks();
    fetchCategories();
  }, []);

  const fetchBooks = async () => {
    const res = await axios.get('http://localhost:5000/api/books');
    setBooks(res.data);
  };

  const fetchCategories = async () => {
    const res = await axios.get('http://localhost:5000/api/categories');
    setCategories(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('token');
    await axios.post('http://localhost:5000/api/books', form, {
      headers: { Authorization: `Bearer ${token}` }
    });
    fetchBooks();
    setForm({ title: '', author: '', isbn: '', category: '', availableCopies: 0, totalCopies: 0 });
  };

  const deleteBook = async (id) => {
    const token = localStorage.getItem('token');
    await axios.delete(`http://localhost:5000/api/books/${id}`, {
      headers: { Authorization: `Bearer ${token}` }
    });
    fetchBooks();
  };

  return (
    <div>
      <h1>Book Management</h1>
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Title" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} required />
        <input type="text" placeholder="Author" value={form.author} onChange={(e) => setForm({ ...form, author: e.target.value })} required />
        <input type="text" placeholder="ISBN" value={form.isbn} onChange={(e) => setForm({ ...form, isbn: e.target.value })} required />
        <select value={form.category} onChange={(e) => setForm({ ...form, category: e.target.value })} required>
          <option value="">Select Category</option>
          {categories.map(cat => (
            <option key={cat._id} value={cat._id}>{cat.name}</option>
          ))}
        </select>
        <input type="number" placeholder="Available Copies" value={form.availableCopies} onChange={(e) => setForm({ ...form, availableCopies: parseInt(e.target.value) })} required />
        <input type="number" placeholder="Total Copies" value={form.totalCopies} onChange={(e) => setForm({ ...form, totalCopies: parseInt(e.target.value) })} required />
        <button type="submit">Add Book</button>
      </form>
      <ul>
        {books.map(book => (
          <li key={book._id}>
            {book.title} by {book.author} - {book.availableCopies}/{book.totalCopies}
            <button onClick={() => deleteBook(book._id)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default BookManagement;
